def sifir_uclu_var_mi(sayilar):
    s = sorted(sayilar)
    n = len(s)
    for i in range(n):
        sol, sag = i + 1, n - 1
        while sol < sag:
            t = s[i] + s[sol] + s[sag]
            if t == 0:
                return True
            if t < 0:
                sol += 1
            else:
                sag -= 1
    return False
